// Rohe PDF-Bytes aus dem Webhook-Body in n8n Binary-Format konvertieren
const item = $input.first();

// Prüfe ob binary schon gesetzt ist (z.B. wenn n8n es automatisch erkennt)
if (item.binary?.data?.data) {
  return [item];
}

// Sonst: rawBody aus json.body konvertieren
const body = item.json?.body;
if (!body) throw new Error('Keine PDF-Daten empfangen');

let buffer;
if (Buffer.isBuffer(body)) {
  buffer = body;
} else if (typeof body === 'string') {
  buffer = Buffer.from(body, 'binary');
} else {
  buffer = Buffer.from(body);
}

return [{
  json: {},
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/pdf',
      fileExtension: 'pdf',
      fileName: 'rechnung.pdf'
    }
  }
}];

// Extrahierten PDF-Text für Gemini aufbereiten (Text-only, kein Binary)
const text = $input.first().json.text || '';

if (!text.trim()) {
  throw new Error('PDF konnte nicht gelesen werden – kein Text extrahiert');
}

const prompt = `Analysiere diese Rechnung und extrahiere alle relevanten Daten als JSON.

Extrahiere genau diese Felder:
- rechnungs_nummer: Rechnungsnummer (String)
- lieferant: Name des Lieferanten (String)
- betrag: Gesamtbetrag als Zahl ohne Währungssymbol (Number)
- waehrung: Währungscode EUR, USD, CHF oder GBP (String)
- datum: Rechnungsdatum im Format YYYY-MM-DD (String)
- eingangskanal: "Email" wenn nicht anders angegeben (String)
- rechnungspositionen: Array mit Positionen, jede mit: beschreibung (String), menge (Number), einheit (String, z.B. Stk.), einzelpreis (Number)

Antworte NUR mit dem JSON-Objekt, ohne Erklärungstext, ohne Markdown-Code-Blöcke.

Rechnungstext:
${text}`;

const requestBody = JSON.stringify({
  contents: [{ parts: [{ text: prompt }] }]
});

return [{ json: { requestBody } }];

// Gemini-Antwort parsen
const response = $input.first().json;
const rawText = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';

let jsonText = rawText.trim();
if (jsonText.startsWith('```')) {
  jsonText = jsonText.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
}

let extracted;
try {
  extracted = JSON.parse(jsonText);
} catch (e) {
  throw new Error(`JSON-Parsing fehlgeschlagen: ${e.message}\nAntwort: ${rawText.substring(0, 300)}`);
}

const result = {
  rechnungs_nummer: String(extracted.rechnungs_nummer || 'UNBEKANNT'),
  lieferant: String(extracted.lieferant || 'UNBEKANNT'),
  betrag: parseFloat(extracted.betrag) || 0,
  waehrung: ['EUR','USD','CHF','GBP'].includes(extracted.waehrung) ? extracted.waehrung : 'EUR',
  datum: extracted.datum || new Date().toISOString().split('T')[0],
  eingangskanal: extracted.eingangskanal || 'Email',
  rechnungspositionen: Array.isArray(extracted.rechnungspositionen) ? extracted.rechnungspositionen : [],
  ki_extraktion_erfolgreich: true,
  ki_extraktion_zeitstempel: new Date().toISOString(),
};

return [{ json: result }];
